#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#include "../common.h"
#include "../util/timer/timer.h"
#include "./kernel_cpu_2.h"

void 
kernel_cpu_2(	int cores_arg,

				knode *knodes,
				long knodes_elem,

				int order,
				long maxheight,
				int count,

				long *currKnode,
				long *offset,
				long *lastKnode,
				long *offset_2,
				int *start,
				int *end,
				int *recstart,
				int *reclength)
{
	// timer
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	omp_set_num_threads(cores_arg);

	#pragma omp parallel for
	for(int i = 0; i < count; i++){
		// process levels of the tree
		for(int j = 0; j < maxheight; j++){

			if(start[i] >= knodes[currKnode[i]].keys[j] && start[i] < knodes[currKnode[i]].keys[j+1]){
				if(knodes_elem > knodes[offset[i]].indices[j]){
					offset[i] = knodes[offset[i]].indices[j];
				}
			}
			if(end[i] >= knodes[lastKnode[i]].keys[j] && end[i] < knodes[lastKnode[i]].keys[j+1]){
				if(knodes_elem > knodes[offset_2[i]].indices[j]){
					offset_2[i] = knodes[offset_2[i]].indices[j];
				}
			}

			// set for next tree level
			currKnode[i] = offset[i];
			lastKnode[i] = offset_2[i];
		}

		// process leaves
		// Find the index of the starting record
		for(int j = 0; j < order; j++){
			if(start[i] == knodes[currKnode[i]].keys[j]){
				recstart[i] = knodes[currKnode[i]].indices[j];
			}
		}

		// Find the index of the ending record
		for(int j = 0; j < order; j++){
			if(end[i] == knodes[lastKnode[i]].keys[j]){
				reclength[i] = knodes[lastKnode[i]].indices[j] - recstart[i] + 1;
			}
		}
	}

	time6 = get_time();

	// Display timing
	printf("Time spent in different stages of CPU KERNEL:\n");
	printf("%15.12f s, %15.12f %% : CPU: PROCESSING\n", (float) (time6-time0) / 1000000, (float) (time6-time0) / (float) (time6-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", (float) (time6-time0) / 1000000);
}
